reject', $request)); ?>"><?php echo csrf_field(); ?> <input type="hidden" name="review_note" value="<?php echo e(__('Rejected from addon cockpit')); ?>"><button class="btn btn-sm btn-outline-danger"><?php echo e(__('Reject')); ?></button></form></div><?php else: ?><span class="text-muted"><?php echo e(ucfirst($request->status)); ?></span><?php endif; ?></td></tr><?php endforeach; $__env->popLoop(); $loop = $__env->getLastLoop(); if ($__empty_2): ?><tr><td colspan="7" class="text-muted"><?php echo e(__('No addon requests recorded yet.')); ?></td></tr><?php endif; ?></tbody></table></div></div>
